const https = require('https');
const http = require('http');
const { URL } = require('url');
const dns = require('dns').promises;
const net = require('net');

const ALLOWED_DOMAINS = [
  'example.com',
  'trusted-site.com',
  'another-allowed-domain.org'
];

const MAX_REDIRECTS = 3;
const TIMEOUT = 10000;

function isPrivateIP(ip) {
  const parts = ip.split('.').map(Number);
  
  if (net.isIPv6(ip)) {
    const lower = ip.toLowerCase();
    return lower.startsWith('::1') ||
           lower.startsWith('fe80:') ||
           lower.startsWith('fc00:') ||
           lower.startsWith('fd00:');
  }
  
  if (parts.length !== 4) return true;
  
  if (parts[0] === 10) return true;
  if (parts[0] === 127) return true;
  if (parts[0] === 172 && parts[1] >= 16 && parts[1] <= 31) return true;
  if (parts[0] === 192 && parts[1] === 168) return true;
  if (parts[0] === 169 && parts[1] === 254) return true;
  if (parts[0] === 0) return true;
  if (parts[0] >= 224) return true;
  
  return false;
}

function isDomainAllowed(hostname) {
  return ALLOWED_DOMAINS.some(allowed => {
    return hostname === allowed || hostname.endsWith('.' + allowed);
  });
}

async function validateDestination(urlString) {
  let parsedUrl;
  
  try {
    parsedUrl = new URL(urlString);
  } catch (e) {
    throw new Error('Invalid URL format');
  }
  
  if (parsedUrl.protocol !== 'http:' && parsedUrl.protocol !== 'https:') {
    throw new Error('Only HTTP and HTTPS protocols are allowed');
  }
  
  const hostname = parsedUrl.hostname;
  
  if (!isDomainAllowed(hostname)) {
    throw new Error('Domain not in allowlist');
  }
  
  if (net.isIP(hostname)) {
    if (isPrivateIP(hostname)) {
      throw new Error('Private IP addresses are not allowed');
    }
  } else {
    try {
      const addresses = await dns.resolve4(hostname);
      
      for (const addr of addresses) {
        if (isPrivateIP(addr)) {
          throw new Error('Domain resolves to private IP address');
        }
      }
    } catch (e) {
      throw new Error('DNS resolution failed or domain resolves to private IP');
    }
  }
  
  return parsedUrl;
}

function fetchWithRedirectControl(url, redirectCount = 0) {
  return new Promise((resolve, reject) => {
    const protocol = url.protocol === 'https:' ? https : http;
    
    const options = {
      hostname: url.hostname,
      port: url.port,
      path: url.pathname + url.search,
      method: 'GET',
      timeout: TIMEOUT,
      headers: {
        'User-Agent': 'Mozilla/5.0 (compatible; MetadataFetcher/1.0)',
        'Accept': 'text/html'
      }
    };
    
    const req = protocol.request(options, async (res) => {
      if (res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
        if (redirectCount >= MAX_REDIRECTS) {
          return reject(new Error('Too many redirects'));
        }
        
        try {
          const redirectUrl = new URL(res.headers.location, url);
          await validateDestination(redirectUrl.href);
          
          fetchWithRedirectControl(redirectUrl, redirectCount + 1)
            .then(resolve)
            .catch(reject);
        } catch (e) {
          reject(new Error('Redirect validation failed: ' + e.message));
        }
        
        return;
      }
      
      if (res.statusCode !== 200) {
        return reject(new Error('HTTP ' + res.statusCode));
      }
      
      let data = '';
      res.setEncoding('utf8');
      
      res.on('data', (chunk) => {
        data += chunk;
        if (data.length > 1024 * 1024) {
          req.destroy();
          reject(new Error('Response too large'));
        }
      });
      
      res.on('end', () => {
        resolve(data);
      });
    });
    
    req.on('error', (e) => {
      reject(e);
    });
    
    req.on('timeout', () => {
      req.destroy();
      reject(new Error('Request timeout'));
    });
    
    req.end();
  });
}

function parseMetadata(html) {
  const metadata = {
    title: null,
    description: null,
    ogTitle: null,
    ogDescription: null,
    ogImage: null,
    ogUrl: null,
    ogType: null
  };
  
  const titleMatch = html.match(/<title[^>]*>([^<]+)<\/title>/i);
  if (titleMatch) {
    metadata.title = titleMatch[1].trim();
  }
  
  const metaRegex = /<meta[^>]+>/gi;
  const metaTags = html.match(metaRegex) || [];
  
  metaTags.forEach(tag => {
    const nameMatch = tag.match(/name=["']([^"']+)["']/i);
    const propertyMatch = tag.match(/property=["']([^"']+)["']/i);
    const contentMatch = tag.match(/content=["']([^"']+)["']/i);
    
    if (!contentMatch) return;
    
    const content = contentMatch[1];
    const attr = (propertyMatch && propertyMatch[1]) || (nameMatch && nameMatch[1]);
    
    if (!attr) return;
    
    switch (attr.toLowerCase()) {
      case 'description':
        metadata.description = content;
        break;
      case 'og:title':
        metadata.ogTitle = content;
        break;
      case 'og:description':
        metadata.ogDescription = content;
        break;
      case 'og:image':
        metadata.ogImage = content;
        break;
      case 'og:url':
        metadata.ogUrl = content;
        break;
      case 'og:type':
        metadata.ogType = content;
        break;
    }
  });
  
  return metadata;
}

async function fetchUrlMetadata(urlString) {
  const validatedUrl = await validateDestination(urlString);
  const html = await fetchWithRedirectControl(validatedUrl);
  const metadata = parseMetadata(html);
  
  return metadata;
}

exports.fetchUrlMetadata = fetchUrlMetadata;